--Top Customers by Balance
SELECT c.full_name, a.balance
FROM customers c
JOIN accounts a ON c.customer_id = a.customer_id
ORDER BY a.balance DESC;

--Total Transactions per Account
SELECT account_id, COUNT(*) as total_transactions
FROM transactions
GROUP BY account_id;

select * from transactions;

--Monthly Summary
SELECT TO_CHAR(transaction_date,'MM-YYYY') AS month, SUM(amount)
FROM transactions
GROUP BY TO_CHAR(transaction_date,'MM-YYYY');

--Customer Loan Details
SELECT c.full_name, l.loan_type, l.loan_amount
FROM customers c
JOIN loans l ON c.customer_id = l.customer_id;

--Customers without Loans
SELECT full_name
FROM customers
WHERE customer_id NOT IN (SELECT customer_id FROM loans);

